1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface QuoteInput {
9	  items: Item[];
10	}
11	
12	export interface QuoteResult {
13	  premium: number;
14	}
15	
16	const PROCESSING_FEE = 5;
17	const DEFAULT_BASE_PREMIUM = 100;
18	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const CURSE_SURCHARGE_RATE = 0.5;
27	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
28	
29	function basePremiumFor(item: Item): number {
30	  const base = BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
31	  if (item.enchantment === 5) {
32	    return base + base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
33	  }
34	  if (item.cursed) {
35	    return base + base * CURSE_SURCHARGE_RATE;
36	  }
37	  return base;
38	}
39	
40	const BLOCK_SIZE = 3;
41	const BLOCK_PREMIUM = 60;
42	
43	function groupByType(items: Item[]): Map<string, Item[]> {
44	  const groups = new Map<string, Item[]>();
45	  for (const item of items) {
46	    const group = groups.get(item.type) ?? [];
47	    group.push(item);
48	    groups.set(item.type, group);
49	  }
50	  return groups;
51	}
52	
53	function basePremiumForGroup(group: Item[]): number {
54	  if (group.length === BLOCK_SIZE) {
55	    return BLOCK_PREMIUM;
56	  }
57	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
58	}
59	
60	export function quote(input: QuoteInput): QuoteResult {
61	  const groups = [...groupByType(input.items).values()];
62	  const basePremium = groups.reduce(
63	    (sum, group) => sum + basePremiumForGroup(group),
64	    0,
65	  );
66	
67	  return { premium: basePremium + PROCESSING_FEE };
68	}
